"""ExperimentGenerator: LLM-driven experiment code generation.

Takes a SearchNode and ProblemSpec, uses the AgentLLM to generate
experiment code, and writes it to the run directory.
"""

from __future__ import annotations

import json
import logging
import re
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any

logger = logging.getLogger(__name__)

from sera.prompts import get_prompt

EXPERIMENT_CODE_PROMPT = get_prompt("experiment_code_runtime")


@dataclass
class GeneratedFile:
    """A single file generated by the LLM (§7.2.1)."""

    relative_path: str  # Relative to runs/{node_id}/, e.g. "experiment.py", "src/utils.py"
    content: str  # File content


@dataclass
class GeneratedExperiment:
    """A complete experiment project generated by the LLM (§7.2.1)."""

    entry_point: str  # Main script relative path, e.g. "experiment.py", "src/main.rs"
    files: list[GeneratedFile] = field(default_factory=list)  # All generated files


class ExperimentGenerator:
    """Generate experiment scripts from search nodes.

    Parameters
    ----------
    agent_llm : object
        LLM client with ``generate(prompt, temperature)`` method.
    problem_spec : object
        The problem specification.
    work_dir : str | Path
        Base workspace directory.
    """

    def __init__(
        self,
        agent_llm: Any,
        problem_spec: Any,
        work_dir: str | Path = "./sera_workspace",
        exec_spec: Any = None,
    ):
        self.agent_llm = agent_llm
        self.problem_spec = problem_spec
        self.work_dir = Path(work_dir)
        self._exec_spec = exec_spec

    def _get_language_config(self) -> Any:
        """Get language config from problem spec, with defaults for Python."""
        if hasattr(self.problem_spec, "language"):
            return self.problem_spec.language
        # Return a simple namespace with Python defaults
        from types import SimpleNamespace

        return SimpleNamespace(
            name="python",
            interpreter_command="python",
            file_extension=".py",
            seed_arg_format="--seed {seed}",
            code_block_tag="python",
        )

    async def generate(self, node: Any) -> GeneratedExperiment:
        """Generate experiment code for a search node.

        Parameters
        ----------
        node : SearchNode
            The node to generate code for. If node.experiment_code is
            already set (e.g., from a debug operation), that code is used
            directly instead of calling the LLM.

        Returns
        -------
        GeneratedExperiment
            The generated experiment project with entry point and files.
        """
        lang_config = self._get_language_config()
        script_filename = "experiment" + lang_config.file_extension

        run_dir = self.work_dir / "runs" / node.node_id
        run_dir.mkdir(parents=True, exist_ok=True)

        multi_file = getattr(lang_config, "multi_file", True)

        if node.experiment_code:
            # Use pre-existing code (e.g., from debug operator)
            # First try multi-file JSON parse (debug may produce JSON structure)
            if multi_file:
                parsed = self._parse_multi_file_json(node.experiment_code)
                if parsed is not None:
                    experiment = parsed
                else:
                    code = self._extract_code(node.experiment_code, lang_config.code_block_tag)
                    experiment = GeneratedExperiment(
                        entry_point=script_filename,
                        files=[GeneratedFile(script_filename, code)],
                    )
            else:
                code = self._extract_code(node.experiment_code, lang_config.code_block_tag)
                experiment = GeneratedExperiment(
                    entry_point=script_filename,
                    files=[GeneratedFile(script_filename, code)],
                )
        elif multi_file:
            experiment = await self._generate_multi_file(node, lang_config, script_filename)
        else:
            code = await self._generate_code(node)
            node.experiment_code = code
            experiment = GeneratedExperiment(
                entry_point=script_filename,
                files=[GeneratedFile(script_filename, code)],
            )

        # Write all files to run_dir
        self._write_files(run_dir, experiment, lang_config)

        logger.info(
            "Generated experiment: entry_point=%s, %d file(s) in %s",
            experiment.entry_point,
            len(experiment.files),
            run_dir,
        )
        return experiment

    async def _generate_multi_file(
        self, node: Any, lang_config: Any, default_entry: str
    ) -> GeneratedExperiment:
        """Generate a multi-file experiment via LLM (§7.2.1).

        Asks the LLM to produce a JSON structure with entry_point and files.
        Falls back to single-file generation on parse failure.
        """
        code = await self._generate_code(node)
        node.experiment_code = code

        # Try to parse as multi-file JSON
        try:
            parsed = self._parse_multi_file_json(code)
            if parsed is not None:
                return parsed
        except (ValueError, KeyError, TypeError) as exc:
            logger.debug("Multi-file JSON parse failed, using single file: %s", exc)

        # Fallback: single file
        clean_code = self._extract_code(code, lang_config.code_block_tag)
        return GeneratedExperiment(
            entry_point=default_entry,
            files=[GeneratedFile(default_entry, clean_code)],
        )

    def _parse_multi_file_json(self, text: str) -> GeneratedExperiment | None:
        # Strip <think>...</think> blocks before parsing
        text = re.sub(r"<think>.*?</think>", "", text, flags=re.DOTALL).strip()
        """Try to extract a multi-file JSON structure from LLM output.

        Expected format:
        {"entry_point": "experiment.py",
         "files": [{"path": "experiment.py", "content": "..."}, ...]}

        Returns None if the text doesn't contain valid multi-file JSON.
        """
        # Try to find JSON in code fences first (allow space between ``` and json)
        match = re.search(r"```\s*json\s*(.*?)\s*```", text, re.DOTALL)

        def _try_parse(s: str):
            try:
                return json.loads(s)
            except json.JSONDecodeError:
                return None

        data = _try_parse(match.group(1).strip()) if match else None

        if data is None:
            # No closing ``` or parse failed: find first { and try to end of string
            brace_start = text.find("{")
            if brace_start >= 0:
                data = _try_parse(text[brace_start:])
            if data is None:
                brace_match = re.search(r"\{.*\}", text, re.DOTALL)
                if brace_match:
                    data = _try_parse(brace_match.group())
            if data is None:
                return None

        if not isinstance(data, dict) or "entry_point" not in data or "files" not in data:
            return None

        entry_point = data["entry_point"]
        files = []
        for f in data["files"]:
            fpath = f.get("path", f.get("relative_path", ""))
            fcontent = f.get("content", "")
            # Strip <think> blocks from file contents
            fcontent = re.sub(r"<think>.*?</think>", "", fcontent, flags=re.DOTALL).strip()
            if fpath:
                files.append(GeneratedFile(relative_path=fpath, content=fcontent))

        if not files:
            return None

        return GeneratedExperiment(entry_point=entry_point, files=files)

    def _write_files(self, run_dir: Path, experiment: GeneratedExperiment, lang_config: Any) -> None:
        """Write all generated files to the run directory with validation."""
        max_files = getattr(lang_config, "max_files", 10)
        max_total_size = getattr(lang_config, "max_total_size_bytes", 1048576)

        # Validate entry_point exists in files
        file_paths = {f.relative_path for f in experiment.files}
        if experiment.entry_point not in file_paths:
            raise ValueError(
                f"entry_point '{experiment.entry_point}' not found in generated files: {file_paths}"
            )

        # Validate file count
        if len(experiment.files) > max_files:
            raise ValueError(
                f"Generated {len(experiment.files)} files, exceeds max_files={max_files}"
            )

        # Validate total size and path safety
        total_size = 0
        for gf in experiment.files:
            # Path traversal check
            if ".." in gf.relative_path:
                raise ValueError(f"Path traversal detected in: {gf.relative_path}")
            total_size += len(gf.content.encode("utf-8"))

        if total_size > max_total_size:
            raise ValueError(
                f"Total file size {total_size} bytes exceeds max_total_size_bytes={max_total_size}"
            )

        # Write files
        for gf in experiment.files:
            file_path = run_dir / gf.relative_path
            file_path.parent.mkdir(parents=True, exist_ok=True)
            file_path.write_text(gf.content, encoding="utf-8")
            logger.debug("Wrote %s (%d bytes)", file_path, len(gf.content))



    def _inject_pip_installs(self, code: str) -> str:
        """Parse imports from generated code and prepend pip install for unknown packages."""
        import ast, re
        known = {
            'argparse','json','time','math','random','os','sys','subprocess',
            'pathlib','collections','itertools','functools','typing','abc',
            'dataclasses','copy','io','struct','ctypes','threading','multiprocessing',
            'numpy','scipy','torch','torchvision','torchaudio','submitit','structlog',
            'pydantic','yaml','rich','typer','transformers','peft','accelerate',
            'tqdm','requests','aiohttp','matplotlib','seaborn','pandas',
        }
        # Packages that DO NOT EXIST on PyPI — user-configurable via execution_spec.blocked_fake_packages
        _blocked_cfg = list(getattr(self._exec_spec, 'blocked_fake_packages', None) or []) if self._exec_spec else []
        BLOCKED_FAKE_PKGS = set(_blocked_cfg)
        _blocked_found = [m.group(1) for m in re.finditer(r'^(?:import|from)\s+(\w+)', code, re.MULTILINE)
                          if m.group(1) in BLOCKED_FAKE_PKGS]
        if _blocked_found:
            logger.warning('Generated code uses nonexistent package(s): %s; injecting error', _blocked_found)
            for pkg in _blocked_found:
                code = code.replace(f'import {pkg}', f'raise ImportError("Package {pkg} does not exist on PyPI")')
                code = code.replace(f'from {pkg}', f'raise ImportError("Package {pkg} does not exist on PyPI; from')

        pip_map = {
            'sklearn': 'scikit-learn', 'cv2': 'opencv-python', 'PIL': 'Pillow',
            'qiskit': 'qiskit', 'tensorflow': 'tensorflow', 'keras': 'tensorflow',
            'lightgbm': 'lightgbm', 'xgboost': 'xgboost', 'catboost': 'catboost',
            'numba': 'numba', 'gym': 'gymnasium', 'optuna': 'optuna',
            'statsmodels': 'statsmodels', 'sympy': 'sympy', 'networkx': 'networkx',
        }
        # Find top-level imports via regex (safe even if code has syntax errors)
        imports = set()
        for m in re.finditer(r'^(?:import|from)\s+(\w+)', code, re.MULTILINE):
            imports.add(m.group(1))
        to_install = []
        for pkg in imports:
            if pkg not in known:
                pip_pkg = pip_map.get(pkg, pkg)
                to_install.append(pip_pkg)
        if not to_install:
            return code
        install_lines = "import subprocess, sys\n"
        for p in to_install:
            install_lines += f"subprocess.run([sys.executable, '-m', 'pip', 'install', '{p}'], check=False, capture_output=True)\n"
        install_lines += "\n"
        # Insert after shebang/encoding lines
        lines = code.splitlines(keepends=True)
        insert_at = 0
        for i, line in enumerate(lines):
            if line.startswith('#!') or line.startswith('# -*-') or line.startswith('# coding'):
                insert_at = i + 1
            elif i == 0:
                pass
            else:
                break
        lines.insert(insert_at, install_lines)
        return "".join(lines)

    @staticmethod
    def _validate_generated_code(code: str, data_location: str) -> tuple:
        """Validate generated experiment code for common issues.

        Returns (is_valid, warning_message).
        """
        warnings = []
        placeholder_patterns = [
            "path_to_data", "your_data_path", "/path/to/", "PATH_TO_",
            "data_path_here", "INSERT_PATH", "YOUR_PATH",
        ]
        for p in placeholder_patterns:
            if p in code:
                warnings.append(f"Placeholder detected: {p!r}")
        if "metrics.json" not in code:
            warnings.append("metrics.json not written in generated code")
        if data_location and ("http" in data_location or "ftp" in data_location):
            if "ImageFolder" in code or "torchvision.datasets" in code:
                warnings.append("ImageFolder detected but task uses URL data (possible wrong task type)")
        if warnings:
            return False, "; ".join(warnings)
        return True, ""

    async def _generate_code(self, node: Any) -> str:
        """Call the LLM to generate experiment code.

        Parameters
        ----------
        node : SearchNode
            The search node with hypothesis and config.

        Returns
        -------
        str
            The generated code.
        """
        lang_config = self._get_language_config()

        problem_description = getattr(self.problem_spec.objective, "description", "Maximize score")
        objective = self.problem_spec.objective.metric_name
        direction = self.problem_spec.objective.direction
        higher_is_better = str(direction == "maximize").lower()
        data_location = ""
        if hasattr(self.problem_spec, "data_location"):
            data_location = self.problem_spec.data_location
        elif hasattr(self.problem_spec, "evaluation_design"):
            data_location = "provided by evaluation framework"

        # Describe seed argument based on language config
        seed_arg_description = lang_config.seed_arg_format.replace("{seed}", "<int>")

        # Problem-specific notes from problem_spec (user-configurable)
        data_description = getattr(self.problem_spec, "data_description", "")
        notes = getattr(self.problem_spec, "notes", "") or ""
        notes_parts = []
        if data_description:
            notes_parts.append(f"Data description: {data_description}")
        if notes:
            notes_parts.append(f"Notes: {notes}")
        notes_section = ("\n".join(notes_parts) + "\n\n") if notes_parts else ""

        # Include experiment template if available
        template = getattr(self.problem_spec, "experiment_template", "")
        template_section = ""
        if template:
            template_section = f"Base template (modify and improve this code based on the hypothesis):\n```{lang_config.code_block_tag}\n{template}\n```"

        prompt = EXPERIMENT_CODE_PROMPT.format(
            language_name=lang_config.name,
            problem_description=problem_description,
            objective=objective,
            direction=direction,
            hypothesis=node.hypothesis,
            experiment_config=json.dumps(node.experiment_config, indent=2),
            data_location=data_location,
            metric_name=self.problem_spec.objective.metric_name,
            higher_is_better=higher_is_better,
            seed_arg_description=seed_arg_description,
            code_block_tag=lang_config.code_block_tag,
            template_section=template_section,
            notes_section=notes_section,
        )

        # Prefer call_function path
        if hasattr(self.agent_llm, "call_function"):
            code = await self.agent_llm.call_function(
                "experiment_code_gen", prompt=prompt, purpose="experiment_code_gen", temperature=0.5
            )
            if not code:
                code = "# Error: code generation returned empty result"
            valid, warn = self._validate_generated_code(code, data_location)
            if not valid:
                logger.warning("[experiment_generator] Code validation warnings: %s", warn)
            # Syntax check: only for Python (compile() is Python-specific)
            if getattr(lang_config, "name", "python") == "python":
                for _retry in range(2):
                    try:
                        compile(code, "<generated>", "exec")
                        break  # syntax ok
                    except SyntaxError as se:
                        logger.warning("[experiment_generator] SyntaxError in generated code (retry %d): %s", _retry+1, se)
                        retry_code = await self.agent_llm.call_function(
                            "experiment_code_gen", prompt=prompt, purpose="experiment_code_gen", temperature=0.5 + (_retry+1)*0.1
                        )
                        if retry_code:
                            code = retry_code
            # Auto-inject pip installs for unknown packages
            code = self._inject_pip_installs(code)
            return code

        # Legacy path (deprecated — use call_function instead)
        response = await self.agent_llm.generate(prompt, purpose="experiment_code_gen", temperature=0.5)
        code = self._extract_code(response, lang_config.code_block_tag)
        return code

    @staticmethod
    def _extract_code(response: str, code_block_tag: str = "python") -> str:
        """Extract code from an LLM response.

        Tries to find a fenced code block first, then falls back
        to the raw response.
        """
        # Try language-specific code block (allow space between ``` and tag)
        pattern = rf"```\s*{re.escape(code_block_tag)}\s*(.*?)\s*```"
        match = re.search(pattern, response, re.DOTALL)
        if match:
            return match.group(1).strip()

        # Try generic code block
        match = re.search(r"```\s*(.*?)\s*```", response, re.DOTALL)
        if match:
            return match.group(1).strip()

        # Return raw response
        return response.strip()
